+import { NonExhaustiveError } from './errors';
+import { matchPattern } from './internals/helpers';
+import * as symbols from './internals/symbols';
+import type { MatchEach } from './types/MatchEach';
+
+type Clause<input> =
+  | { type: 'with'; patterns: unknown[]; predicate?: (value: input) => unknown; handler: (selection: unknown, value: input) => unknown }
+  | { type: 'when'; predicate: (value: input) => unknown; handler: (value: input) => unknown };
+
+type Step<input> = Clause<input> | { type: 'tap'; callback: (result: unknown) => void };
+
+export function matchEach<input, output = symbols.unset>(value: input): MatchEach<input, output>;
+export function matchEach<input, output = symbols.unset>(): MatchEach<input, output>;
+export function matchEach<input, output = symbols.unset>(value?: input): MatchEach<input, output> {
+  return new MatchEachExpression<input>(arguments.length > 0, value, []) as any;
+}
+
+class MatchEachExpression<input> {
+  constructor(
+    private readonly hasInput: boolean,
+    private readonly input: input | undefined,
+    private readonly steps: readonly Step<input>[]
+  ) {}
+
+  with(...args: any[]): MatchEachExpression<input> {
+    const handler = args[args.length - 1];
+    const patterns = [args[0]];
+    let predicate: ((value: input) => unknown) | undefined;
+
+    if (args.length === 3 && typeof args[1] === 'function') predicate = args[1];
+    else if (args.length > 2) patterns.push(...args.slice(1, -1));
+
+    return this.append({ type: 'with', patterns, predicate, handler });
+  }
+
+  when(predicate: (value: input) => unknown, handler: (value: input) => unknown) {
+    return this.append({ type: 'when', predicate, handler });
+  }
+
+  tap(callback: (result: unknown) => void) {
+    return this.append({ type: 'tap', callback });
+  }
+
+  otherwise(handler: (value: input) => unknown): unknown[] {
+    const results = this.evaluateCurrent();
+    return results.length ? results : [handler(this.input as input)];
+  }
+
+  exhaustive(unexpectedValueHandler = defaultCatcher): unknown[] {
+    const results = this.evaluateCurrent();
+    return results.length ? results : [unexpectedValueHandler(this.input)];
+  }
+
+  run(): unknown[] {
+    return this.exhaustive();
+  }
+
+  returnType() {
+    return this;
+  }
+
+  narrow() {
+    return this;
+  }
+
+  toFunction() {
+    return (input: input) => this.evaluateOrThrow(input);
+  }
+
+  toExhaustiveFunction() {
+    return (input: input) => this.evaluateOrThrow(input);
+  }
+
+  toPartialFunction() {
+    return (input: input) => {
+      const results = this.evaluate(input);
+      return results.length ? results : undefined;
+    };
+  }
+
+  private append(step: Step<input>) {
+    return new MatchEachExpression(this.hasInput, this.input, [...this.steps, step]);
+  }
+
+  private evaluateCurrent() {
+    if (!this.hasInput) return [];
+    return this.evaluate(this.input as input);
+  }
+
+  private evaluateOrThrow(input: input) {
+    const results = this.evaluate(input);
+    if (!results.length) defaultCatcher(input);
+    return results;
+  }
+
+  private evaluate(input: input): unknown[] {
+    const results: unknown[] = [];
+
+    for (const step of this.steps) {
+      if (step.type === 'tap') {
+        results.forEach(step.callback);
+        continue;
+      }
+
+      if (step.type === 'when') {
+        if (step.predicate(input)) results.push(step.handler(input));
+        continue;
+      }
+
+      let selections: unknown = input;
+      let matched = false;
+      for (const pattern of step.patterns) {
+        let hasSelections = false;
+        const selected: Record<string, unknown> = {};
+        if (matchPattern(pattern, input, (key, value) => {
+          hasSelections = true;
+          selected[key] = value;
+        })) {
